<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerSetting; use Illuminate\Support\Facades\DB;
class CustomerNumberService { public function next(int $companyId):string{return DB::transaction(function()use($companyId){$settings=CustomerSetting::query()->lockForUpdate()->firstOrCreate(['company_id'=>$companyId]);$next=(int)$settings->next_customer_number;do{$number=$settings->customer_number_prefix.'-'.str_pad((string)$next,6,'0',STR_PAD_LEFT);$next++;}while(Customer::query()->where('company_id',$companyId)->where('customer_number',$number)->exists());$settings->update(['next_customer_number'=>$next]);return $number;});} }
